{
    "level": "A2",
    "intro": "W tej lekcji zobaczysz, jak budować <strong>Past Simple Passive</strong>: zdania twierdzące, przeczące i pytające. To dobra forma, gdy chcesz mówić o przeszłości, ale nie skupiać się na wykonawcy.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "Podstawowy wzór to <strong>subject + was / were + V3</strong>.",
            "example": "The house was built in 1990."
        },
        {
            "label": "Przeczenie",
            "color": "rose",
            "text": "Przeczenie tworzymy przez <strong>wasn't / weren't + V3</strong>.",
            "example": "The letter was not sent."
        },
        {
            "label": "Pytanie",
            "color": "blue",
            "text": "Pytanie ma szyk <strong>Was / Were + subject + V3?</strong>",
            "example": "Was the house built in 1990?"
        }
    ]
}

{
    "title": "1. Wybór was / were",
    "intro": "W Past Simple Passive wybieramy formę <strong>was</strong> albo <strong>were</strong> tak samo jak w zwykłym Past Simple czasownika <strong>be</strong>.",
    "items": [
        {
            "label": "Liczba pojedyncza",
            "title": "was",
            "subtitle": "The house was built. / I was invited."
        },
        {
            "label": "Liczba mnoga",
            "title": "were",
            "subtitle": "The documents were signed. / They were arrested."
        },
        {
            "label": "Podmiot osobowy",
            "title": "I / he / she / it → was",
            "subtitle": "I was informed. / She was chosen."
        },
        {
            "label": "Podmiot w liczbie mnogiej",
            "title": "you / we / they → were",
            "subtitle": "We were told. / They were invited."
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Szyk: <strong>subject + was / were + V3 (+ by + agent)</strong>.",
            "examples": [
                {
                    "en": "The house was built in 1990.",
                    "ua": "Dom został zbudowany w 1990 roku."
                },
                {
                    "en": "The thieves were caught yesterday.",
                    "ua": "Złodzieje zostali złapani wczoraj."
                },
                {
                    "en": "I was invited to the party.",
                    "ua": "Zostałem zaproszony na imprezę."
                }
            ]
        },
        {
            "label": "Kiedy używamy?",
            "color": "sky",
            "description": "Używamy tej formy do <strong>zakończonych działań w przeszłości</strong>, gdy ważniejszy jest obiekt albo rezultat.",
            "examples": [
                {
                    "en": "America was discovered in 1492.",
                    "ua": "To fakt historyczny przedstawiony w stronie biernej."
                },
                {
                    "en": "The letter was sent last week.",
                    "ua": "Liczy się fakt wysłania, nie wykonawca."
                },
                {
                    "en": "The window was broken during the storm.",
                    "ua": "Skupiamy się na skutku zdarzenia."
                }
            ]
        }
    ]
}

{
    "title": "3. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Przeczenie tworzymy tak: <strong>subject + was / were not + V3</strong>.",
            "examples": [
                {
                    "en": "The email was not sent.",
                    "ua": "E-mail nie został wysłany."
                },
                {
                    "en": "The documents were not signed.",
                    "ua": "Dokumenty nie zostały podpisane."
                },
                {
                    "en": "I was not informed about the meeting.",
                    "ua": "Nie zostałem poinformowany o spotkaniu."
                }
            ]
        },
        {
            "label": "Skrócone formy",
            "color": "amber",
            "description": "W mowie i w stylu neutralnym często używamy skrótów <strong>wasn't</strong> i <strong>weren't</strong>.",
            "examples": [
                {
                    "en": "The door wasn't locked.",
                    "ua": "Drzwi nie były zamknięte."
                },
                {
                    "en": "The rooms weren't cleaned yesterday.",
                    "ua": "Pokoje nie były wczoraj sprzątane."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania pytające",
    "sections": [
        {
            "label": "Pytania yes / no",
            "color": "blue",
            "description": "Pytanie tworzymy przez przestawienie <strong>was / were</strong> na początek zdania.",
            "examples": [
                {
                    "en": "Was the car repaired?",
                    "ua": "Czy samochód został naprawiony?"
                },
                {
                    "en": "Were the documents signed?",
                    "ua": "Czy dokumenty zostały podpisane?"
                },
                {
                    "en": "Was she invited to the party?",
                    "ua": "Czy została zaproszona na imprezę?"
                }
            ]
        },
        {
            "label": "Pytania wh-",
            "color": "sky",
            "description": "W pytaniach szczegółowych dodajemy słowo pytające przed <strong>was / were</strong>.",
            "examples": [
                {
                    "en": "When was the house built?",
                    "ua": "Kiedy zbudowano dom?"
                },
                {
                    "en": "Where was the car found?",
                    "ua": "Gdzie znaleziono samochód?"
                },
                {
                    "en": "Why were they arrested?",
                    "ua": "Dlaczego zostali aresztowani?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "W krótkich odpowiedziach używamy <strong>Yes / No + subject pronoun + was / were</strong>.",
            "examples": [
                {
                    "en": "Was the letter sent? — Yes, it was. / No, it wasn't.",
                    "ua": "Czy list został wysłany? — Tak, został. / Nie, nie został."
                },
                {
                    "en": "Were they informed? — Yes, they were. / No, they weren't.",
                    "ua": "Czy zostali poinformowani? — Tak, zostali. / Nie, nie zostali."
                }
            ]
        }
    ]
}

{
    "title": "5. Active vs passive: Past Simple",
    "intro": "Porównaj stronę czynną i bierną w zdaniach o przeszłości:",
    "rows": [
        {
            "en": "Active: Tom wrote the letter yesterday.",
            "ua": "Tom napisał list wczoraj.",
            "note": "→ Passive: The letter was written yesterday."
        },
        {
            "en": "Active: They built this house in 1990.",
            "ua": "Zbudowali ten dom w 1990 roku.",
            "note": "→ Passive: This house was built in 1990."
        },
        {
            "en": "Active: Someone stole my bike.",
            "ua": "Ktoś ukradł mój rower."
            ,"note": "→ Passive: My bike was stolen."
        }
    ],
    "warning": "📌 Markery czasu, takie jak <em>yesterday</em> albo <em>in 1990</em>, zostają w zdaniu po zmianie strony."
}

{
    "title": "6. Markery czasu",
    "sections": [
        {
            "label": "Typowe wyrażenia",
            "color": "emerald",
            "description": "Past Simple Passive bardzo często pojawia się z wyrażeniami czasu przeszłego.",
            "examples": [
                {
                    "en": "yesterday",
                    "ua": "The report was finished yesterday."
                },
                {
                    "en": "last week / month / year",
                    "ua": "The car was sold last week."
                },
                {
                    "en": "in 1990 / in the 19th century",
                    "ua": "The bridge was built in 1900."
                },
                {
                    "en": "ago",
                    "ua": "The email was sent two days ago."
                }
            ]
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zły wybór was / were.",
            "wrong": "The documents was signed.",
            "right": "✅ The documents were signed."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie V2 zamiast V3.",
            "wrong": "The house was builded in 1990.",
            "right": "✅ The house was built in 1990."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Brak operatora w pytaniu.",
            "wrong": "The letter sent yesterday?",
            "right": "✅ Was the letter sent yesterday?"
        }
    ]
}

{
    "title": "Pozostałe strony z podstaw strony biernej",
    "items": [
        {
            "label": "What is the passive voice?",
            "current": false
        },
        {
            "label": "Formation: be + V3",
            "current": false
        },
        {
            "label": "Present Simple Passive",
            "current": false
        },
        {
            "label": "Past Simple Passive",
            "current": true
        }
    ]
}
